package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Tag;
import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

@Tag("timeout")
class ClonePair10517DifferenceFindingTest {

    private final ClonePair10517 subject = new ClonePair10517();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: no_termination.
     * Difference manifestation: the methods differ in whether they terminate.
     */
    @Test
    @BehavioralDifference(DifferenceType.NO_TERMINATION)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{"", "", ""};
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1((java.lang.String) values[0], (java.lang.String) values[1], (java.lang.String) values[2]), 200L, inputs);
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2((java.lang.String) values[0], (java.lang.String) values[1], (java.lang.String) values[2]), 200L, inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "String()",
            null,
            "java.lang.Object[][String(),String(),String()]",
            "java.lang.Object[][String(),String(),String()]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "TIMEOUT",
            null,
            null,
            "java.lang.Object[][String(),String(),String()]",
            "java.lang.Object[][String(),String(),String()]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
